INSERT INTO `movie` (`id`, `title`, `title_en`, `synopsis_fr`, `synopsis_en`, `duration`, `main_language`, `yt_url`, `thumbnail`, `subtitles`, `stack`, `methodology`, `ia_type`, `status`, `created_at`, `director_id`) VALUES (1, 'A Hopefully Not So Distant Future', 'A Hopefully Not So Distant Future EN', 'Une vision fascinante et optimiste du futur, imaginée par Alessandro Cannarozzi, CarloDi Piazza, Silvia Perizzolo, où la technologie et l''humanité s''unissent pour construire un monde meilleur.', 'A fascinating and optimistic vision of the future, imagined by Alessandro Cannarozzi, CarloDi Piazza, Silvia Perizzolo, where technology and humanity unite to build a better world.', 60, 'Anglais', 'https://www.youtube.com/watch?v=VrWkS_gRViM', 'https://img.youtube.com/vi/VrWkS_gRViM/maxresdefault.jpg', 'Français', 'Sora, Midjourney, ElevenLabs', 'Génération texte-vers-vidéo et voix off', '100% IA', 'approved', NOW(), 100);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (1, 'https://images.unsplash.com/photo-1620712943543-bcc4628c9457?q=80&w=1280', NOW(), 1);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (2, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1280', NOW(), 1);
INSERT INTO `movie` (`id`, `title`, `title_en`, `synopsis_fr`, `synopsis_en`, `duration`, `main_language`, `yt_url`, `thumbnail`, `subtitles`, `stack`, `methodology`, `ia_type`, `status`, `created_at`, `director_id`) VALUES (2, 'Utopsie', 'Utopsie EN', 'Un court-métrage captivant réalisé par Smeyers Anthony dans le cadre du festival MarsAI, illustrant notre relation avec les technologies futures.', 'A captivating short film directed by Smeyers Anthony for the MarsAI Festival, depicting our relationship with future technologies.', 60, 'Français', 'https://www.youtube.com/watch?v=05AMEtq5vcM', 'https://img.youtube.com/vi/05AMEtq5vcM/maxresdefault.jpg', 'Anglais', 'Runway Gen-2, Stable Diffusion, Claude', 'Animation d''images fixes générées par IA', 'Hybride', 'approved', NOW(), 101);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (3, 'https://images.unsplash.com/photo-1620712943543-bcc4628c9457?q=80&w=1280', NOW(), 2);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (4, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1280', NOW(), 2);
INSERT INTO `movie` (`id`, `title`, `title_en`, `synopsis_fr`, `synopsis_en`, `duration`, `main_language`, `yt_url`, `thumbnail`, `subtitles`, `stack`, `methodology`, `ia_type`, `status`, `created_at`, `director_id`) VALUES (3, 'Artificial Comfort', 'Artificial Comfort EN', 'Une exploration intime et philosophique des relations humaines et du sentiment d''appartenance à l''ère du numérique, par Carmen Moreno.', 'An intimate and philosophical exploration of human relationships and the sense of belonging in the digital age, by Carmen Moreno.', 60, 'Français', 'https://www.youtube.com/watch?v=PCqh8ikbYAg', 'https://img.youtube.com/vi/PCqh8ikbYAg/maxresdefault.jpg', 'Anglais', 'Kling AI, Luma Dream Machine, ChatGPT', 'Interpolation temporelle et écriture de script par IA', '100% IA', 'approved', NOW(), 102);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (5, 'https://images.unsplash.com/photo-1620712943543-bcc4628c9457?q=80&w=1280', NOW(), 3);
INSERT INTO `image` (`id`, `url`, `created_at`, `movie_id`) VALUES (6, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1280', NOW(), 3);
INSERT INTO `movie` (`id`, `title`, `title_en`, `synopsis_fr`, `synopsis_en`, `duration`, `main_language`, `yt_url`, `thumbnail`, `subtitles`, `stack`, `methodology`, `ia_type`, `status`, `created_at`, `director_id`) VALUES (4, 'MR. CROCO', 'MR. CROCO EN', 'Une comédie satirique et décalée signée Pietro Maria Vincenti trabace, mettant en scène des personnages atypiques dans un monde futuriste régenté par des algorithmes absurdes.', 'A satirical and offbeat comedy by Pietro Maria Vincenti trabace, featuring atypical characters in a futuristic world governed by absurd algorithms.', 60, 'Anglais', 'https://www.youtube.com/watch?v=GgVP7mt7mN4', 'https://img.youtube.com/vi/GgVP7mt7mN4/maxresdefault.jpg', 'Français', 'Midjourney, Pika Labs, Leonardo.ai', 'Génération de plans hybrides et colorisation', 'Hybride', 'approved', NOW(), 103);
